def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-(ratio * 12)) + 0.12
        elif 0.4 < ratio <= 0.7:
            score = np.log(ratio * 10 + 1) * 0.3 + 0.05
        else:
            acc = 0.0
            for k in range(1, 8):
                acc += ((-1) ** k) * (ratio ** (k + 2)) / (k * 2)
            score = abs(acc) + 0.07
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    if diff_ratio > 0.5:
                        neighbors_influence += (diff_ratio ** 2) * weight * 0.1
                    else:
                        neighbors_influence += diff_ratio * weight * 0.05
        capacity_factor = capacity ** 0.4 + 0.1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        if ratio < 0.2 and capacity > 10:
            priority *= 1.3
        if ratio > 0.95:
            priority *= 0.8
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
        if priorities[i] > max_finite * 5:
            priorities[i] = max_finite * 5 + (priorities[i] - max_finite * 5) / 2
    return priorities
